  if (completedTurn % decay.everyTurns !== 0) {
    const normalizedMax = fullnessMaxFor(state.player.fullness.current);
    if (normalizedMax === state.player.fullness.max) {
      return { state, events: [] };
    }

    return {
      state: withPlayerFullness(
        state,
        state.player.fullness.current,
        normalizedMax
      ),
      events: []

