export type FallbackProviderErrorCode =
  | "fallback_content_invalid"
  | "fallback_depth_unavailable";

export class FallbackProviderError extends Error {
  readonly kind = "fallback-provider-error";
  readonly code: FallbackProviderErrorCode;
  readonly depth: number | null;
  readonly file: string | null;
  readonly entityId: string | null;
  readonly source: unknown;

  constructor(
    code: FallbackProviderErrorCode,
    depth: number | null,
    message: string,
    source: unknown,
  ) {
    super(message);
    this.name = "FallbackProviderError";
    this.code = code;
    this.depth = depth;
    this.source = source;

    if (source instanceof FallbackContentValidationError) {
      this.file = source.file;
      this.entityId = source.entityId;
      return;
    }

    this.file = null;
    this.entityId = null;
  }
}

export type FallbackFloorContentProviderOptions = {
  readonly root?: URL;
  readonly hoard?: HoardFeatureParams;
};

const DEFAULT_HOARD: HoardFeatureParams = {
  id: "hoard",
  name: "The Hoard",
  hint: { distance: "far_from_entrance" },
};

export class FallbackFloorContentProvider implements FloorContentProvider {
  readonly pack: FallbackContentPack;
  private readonly floors: ReadonlyMap<number, ResolvedFallbackFloor>;
  private readonly hoard: HoardFeatureParams;

  constructor(options: FallbackFloorContentProviderOptions = {}) {
    this.hoard = options.hoard ?? DEFAULT_HOARD;

    try {
      this.pack = loadFallbackContentPack(options.root);
      this.floors = validateFloors(this.pack);
    } catch (error) {
      if (error instanceof FallbackProviderError) {
        throw error;
      }

      throw wrapProviderError("fallback_content_invalid", null, error);
    }
  }

  getFloor(depth: number, seed: string): FloorContent {
    const floor = this.floors.get(depth);
    if (floor === undefined) {
      throw new FallbackProviderError(
        "fallback_depth_unavailable",
        depth,
        `fallback floor ${depth} is not available`,
        null,
      );
    }

    return {
      params: {
        ...floor.params,
        seed,
        ...(depth === config.runStructure.depthFloors
          ? { hoard: this.hoard }
          : {}),
      },
      roster: floor.roster,
      items: floor.items,
      traps: floor.traps,
      npcs: floor.npcs,
      ...(floor.quest === null ? {} : { quest: floor.quest }),
    };
  }
}

export const createFallbackFloorContentProvider = (
  options: FallbackFloorContentProviderOptions = {},
): FallbackFloorContentProvider => new FallbackFloorContentProvider(options);

const validateFloors = (
  pack: FallbackContentPack,
): ReadonlyMap<number, ResolvedFallbackFloor> => {
  const floors = new Map<number, ResolvedFallbackFloor>();

  for (let depth = 1; depth <= config.runStructure.depthFloors; depth += 1) {
    try {
      floors.set(depth, getFallbackFloor(pack, depth));
    } catch (error) {
      throw wrapProviderError("fallback_content_invalid", depth, error);
    }
  }

  return floors;
};

const wrapProviderError = (
  code: FallbackProviderErrorCode,
  depth: number | null,
  source: unknown,
): FallbackProviderError => {
  const sourceMessage = source instanceof Error ? source.message : String(source);
  const message =
    depth === null
      ? `fallback content pack is invalid: ${sourceMessage}`
      : `fallback floor ${depth} is invalid: ${sourceMessage}`;

  return new FallbackProviderError(code, depth, message, source);
};

import { readFileSync, readdirSync } from "node:fs";

import { z } from "zod";

import { bounds, config } from "../config/index.js";
import type { LayoutFlavor } from "../engine/floorgen/flavors.js";
import { LAYOUT_FLAVORS } from "../engine/floorgen/flavors.js";
import type { FloorParams } from "../engine/floorgen/generate.js";
import {
  EnemyDefinitionSchema,
  ItemDefinitionSchema,
  NpcDefinitionSchema,
  QuestDefinitionSchema,
  TrapDefinitionSchema,
  type DepthBand,
  type EnemyDefinition,
  type ItemDefinition,
  type NpcDefinition,
  type QuestDefinition,
  type TrapDefinition,
} from "../schemas/entities/index.js";
import { depthBandForDepth } from "../engine/state/init.js";

const defaultPackRoot = new URL("../../content/fallback/", import.meta.url);

export class FallbackContentValidationError extends Error {
  readonly file: string;
  readonly entityId: string | null;

  constructor(file: string | URL, entityId: string | null, message: string) {
    const fileLabel = typeof file === "string" ? file : file.pathname;
    super(
      entityId === null
        ? `${fileLabel}: ${message}`
        : `${fileLabel} [${entityId}]: ${message}`,
    );
    this.name = "FallbackContentValidationError";
    this.file = fileLabel;
    this.entityId = entityId;
  }
}

const LayoutFlavorSchema = z.enum(LAYOUT_FLAVORS);

export const FallbackFloorDefinitionSchema = z.strictObject({
  depth: z.number().int().min(1).max(config.runStructure.depthFloors),
  flavor: LayoutFlavorSchema,
  enemyRosterIds: z.array(z.string().min(1)).min(1),
  itemIds: z
    .array(z.string().min(1))
    .min(config.itemsEconomy.itemsPerFloor.min)
    .max(config.itemsEconomy.itemsPerFloor.max),
  trapIds: z
    .array(z.string().min(1))
    .max(bounds.trapsNpcsQuests.traps.perFloor.max),
  npcIds: z
    .array(z.string().min(1))
    .max(bounds.trapsNpcsQuests.npcs.perFloor.max),
  questId: z.string().min(1).nullable(),
});

export type FallbackFloorDefinition = z.infer<typeof FallbackFloorDefinitionSchema>;

export type FallbackContentPack = {
  readonly root: string;
  readonly items: ReadonlyMap<string, ItemDefinition>;
  readonly enemies: ReadonlyMap<string, EnemyDefinition>;
  readonly traps: ReadonlyMap<string, TrapDefinition>;
  readonly npcs: ReadonlyMap<string, NpcDefinition>;
  readonly quests: ReadonlyMap<string, QuestDefinition>;
  readonly floors: ReadonlyMap<number, FallbackFloorDefinition>;
};

export type ResolvedFallbackFloor = {
  readonly depth: number;
  readonly band: DepthBand;
  readonly flavor: LayoutFlavor;
  readonly params: Omit<FloorParams, "seed">;
  readonly roster: readonly EnemyDefinition[];
  readonly items: readonly ItemDefinition[];
  readonly traps: readonly TrapDefinition[];
  readonly npcs: readonly NpcDefinition[];
  readonly quest: QuestDefinition | null;
};

const EntityArraySchema = <T extends z.ZodType>(schema: T, label: string) =>
  z.array(schema).superRefine((entries, ctx) => {
    const seen = new Set<string>();

    for (const [index, entry] of entries.entries()) {
      const parsed = schema.safeParse(entry);
      if (!parsed.success) {
        ctx.addIssue({
          code: "custom",
          path: [index],
          message: `${label} validation failed`,
        });
        continue;
      }

      const id = (parsed.data as { id: string }).id;
      if (seen.has(id)) {
        ctx.addIssue({
          code: "custom",
          path: [index, "id"],
          message: `duplicate ${label} id ${id}`,
        });
      }
      seen.add(id);
    }
  });

const readJsonFile = (path: URL | string): unknown => {
  try {
    return JSON.parse(readFileSync(path, "utf8")) as unknown;
  } catch (error) {
    const message = error instanceof Error ? error.message : String(error);
    throw new FallbackContentValidationError(path, null, message);
  }
};

const parseEntityFile = <T>(
  filePath: URL,
  schema: z.ZodType<T>,
  label: string,
): ReadonlyMap<string, T> => {
  const raw = readJsonFile(filePath);
  const parsed = EntityArraySchema(schema, label).safeParse(raw);

  if (!parsed.success) {
    throw new FallbackContentValidationError(
      filePath,
      null,
      parsed.error.message,
    );
  }

  const map = new Map<string, T>();

  for (const entry of parsed.data) {
    const itemParsed = schema.safeParse(entry);
    if (!itemParsed.success) {
      const id =
        typeof entry === "object" &&
        entry !== null &&
        "id" in entry &&
        typeof entry.id === "string"
          ? entry.id
          : null;
      throw new FallbackContentValidationError(
        filePath,
        id,
        itemParsed.error.message,
      );
    }

    map.set((itemParsed.data as { id: string }).id, itemParsed.data);
  }

  return map;
};

const loadFloorFiles = (root: URL): ReadonlyMap<number, FallbackFloorDefinition> => {
  const floorsDir = new URL("floors/", root);
  const files = readdirSync(floorsDir, { withFileTypes: true })
    .filter((entry) => !entry.isDirectory() && entry.name.endsWith(".json"))
    .map((entry) => entry.name)
    .sort();

  const map = new Map<number, FallbackFloorDefinition>();

  for (const fileName of files) {
    const filePath = new URL(fileName, floorsDir);
    const raw = readJsonFile(filePath);
    const parsed = FallbackFloorDefinitionSchema.safeParse(raw);

    if (!parsed.success) {
      throw new FallbackContentValidationError(
        filePath,
        null,
        parsed.error.message,
      );
    }

    const depth = parsed.data.depth;
    if (map.has(depth)) {
      throw new FallbackContentValidationError(
        filePath,
        null,
        `duplicate floor depth ${depth}`,
      );
    }

    map.set(depth, parsed.data);
  }

  for (let depth = 1; depth <= config.runStructure.depthFloors; depth += 1) {
    if (!map.has(depth)) {
      throw new FallbackContentValidationError(
        new URL(`${depth}.json`, floorsDir).pathname,
        null,
        `missing floor definition for depth ${depth}`,
      );
    }
  }

  return map;
};

const resolveReferences = <T>(
  fileLabel: string,
  ids: readonly string[],
  table: ReadonlyMap<string, T>,
  entityLabel: string,
): readonly T[] =>
  ids.map((id) => {
    const entity = table.get(id);
    if (entity === undefined) {
      throw new FallbackContentValidationError(
        fileLabel,
        id,
        `unknown ${entityLabel} id ${id}`,
      );
    }
    return entity;
  });

export const loadFallbackContentPack = (
  root: URL = defaultPackRoot,
): FallbackContentPack => ({
  root: root.pathname,
  items: parseEntityFile(
    new URL("items.json", root),
    ItemDefinitionSchema,
    "item",
  ),
  enemies: parseEntityFile(
    new URL("enemies.json", root),
    EnemyDefinitionSchema,
    "enemy",
  ),
  traps: parseEntityFile(
    new URL("traps.json", root),
    TrapDefinitionSchema,
    "trap",
  ),
  npcs: parseEntityFile(new URL("npcs.json", root), NpcDefinitionSchema, "npc"),
  quests: parseEntityFile(
    new URL("quests.json", root),
    QuestDefinitionSchema,
    "quest",
  ),
  floors: loadFloorFiles(root),
});

export const getFallbackFloor = (
  pack: FallbackContentPack,
  depth: number,
): ResolvedFallbackFloor => {
  const floor = pack.floors.get(depth);
  if (floor === undefined) {
    throw new FallbackContentValidationError(
      `${pack.root}/floors`,
      String(depth),
      `no floor definition for depth ${depth}`,
    );
  }

  const band = depthBandForDepth(depth);
  const fileLabel = `${pack.root}/floors/${depth}.json`;

  return {
    depth,
    band,
    flavor: floor.flavor,
    params: {
      bandOrSize: band,
      roomCountRange: config.runStructure.floorGeometry[band].rooms,
      flavor: floor.flavor,
    },
    roster: resolveReferences(
      fileLabel,
      floor.enemyRosterIds,
      pack.enemies,
      "enemy",
    ),
    items: resolveReferences(fileLabel, floor.itemIds, pack.items, "item"),
    traps: resolveReferences(fileLabel, floor.trapIds, pack.traps, "trap"),
    npcs: resolveReferences(fileLabel, floor.npcIds, pack.npcs, "npc"),
    quest:
      floor.questId === null
        ? null
        : (pack.quests.get(floor.questId) ??
          (() => {
            throw new FallbackContentValidationError(
              fileLabel,
              floor.questId,
              `unknown quest id ${floor.questId}`,
            );
          })()),
  };
};

import { bounds, config } from "../../config/index.js";
import type {
  Behavior,
  DepthBand,
  EnemyDefinition,
} from "../../schemas/entities/index.js";
import type {
  Effect,
  EffectBundle,
  TargetingShape,
  Trigger,
} from "../../schemas/vocab/index.js";

const costWeights = config.enemyDesign.costWeights;

export const costOf = (definition: EnemyDefinition): number =>
  statCost(definition) +
  definition.behaviors.reduce(
    (total, behavior) => total + behaviorCost(behavior),
    0,
  ) +
  definition.abilities.reduce(
    (total, bundle) => total + abilityBundleCost(bundle),
    0,
  );

export const statsWithinBand = (
  definition: EnemyDefinition,
  band: DepthBand,
): boolean => {
  if (definition.stats.band !== band) {
    return false;
  }

  const budget = bounds.enemyDesign.statBudgetsByBand[band];

  return (
    inRange(definition.stats.hp, budget.hp) &&
    inRange(definition.stats.attack, budget.attack) &&
    inRange(definition.stats.defense, budget.defense) &&
    inRange(definition.stats.xpYield, budget.xpYield)
  );
};

export const rosterCost = (definitions: readonly EnemyDefinition[]): number =>
  definitions.reduce((total, definition) => total + costOf(definition), 0);

export const rosterAffordable = (
  definitions: readonly EnemyDefinition[],
  band: DepthBand,
): boolean =>
  definitions.every((definition) => statsWithinBand(definition, band)) &&
  rosterCost(definitions) <= config.enemyDesign.spawnBudgetPoints[band];

export const xpYieldFromCost = (cost: number, band: DepthBand): number => {
  const mapping = costWeights.xpYieldByCost[band];
  const xpBounds = bounds.enemyDesign.statBudgetsByBand[band].xpYield;
  const mapped = Math.floor(cost / mapping.pointsPerXp) + mapping.offset;

  return clamp(mapped, xpBounds.min, xpBounds.max);
};

export const xpYieldOf = (definition: EnemyDefinition): number =>
  xpYieldFromCost(costOf(definition), definition.stats.band);

export const statCost = (definition: EnemyDefinition): number => {
  const band = definition.stats.band;
  const bandBudget = bounds.enemyDesign.statBudgetsByBand[band];
  const statWeights = costWeights.stats;

  return (
    statWeights.baseByBand[band] +
    ceilDiv(
      nonNegativeDelta(definition.stats.hp, bandBudget.hp.min),
      statWeights.hpDeltaDivisor,
    ) +
    nonNegativeDelta(definition.stats.attack, bandBudget.attack.min) *
      statWeights.attackDelta +
    nonNegativeDelta(definition.stats.defense, bandBudget.defense.min) *
      statWeights.defenseDelta
  );
};

export const behaviorCost = (behavior: Behavior): number =>
  costWeights.behaviors[behavior.kind];

export const abilityBundleCost = (bundle: EffectBundle): number =>
  bundle.effects.reduce((total, effect) => total + effectCost(effect), 0) +
  triggerCost(bundle.trigger) +
  targetingCost(bundle.targeting);

export const effectCost = (effect: Effect): number => {
  const verbBase = costWeights.effects.verbs[effect.kind];
  const divisors = costWeights.effects.magnitudeDivisors;

  switch (effect.kind) {
    case "damage":
      return verbBase + ceilDiv(effect.damage?.amount ?? 0, divisors.damageAmount);
    case "heal":
      return verbBase + ceilDiv(effect.heal?.amount ?? 0, divisors.healAmount);
    case "apply_status":
      return (
        verbBase +
        ceilDiv(effect.applyStatus?.duration ?? 0, divisors.statusDuration)
      );
    case "cure_status":
      return verbBase + (effect.cureStatus?.status === "all" ? 1 : 0);
    case "buff_stat": {
      const payload = effect.buffStat;
      const magnitudeDuration =
        payload === null ? 0 : Math.abs(payload.magnitude) * payload.duration;

      return (
        verbBase +
        ceilDiv(magnitudeDuration, divisors.buffMagnitudeDurationProduct)
      );
    }
    case "nutrition":
      return (
        verbBase +
        ceilDiv(effect.nutrition?.fullness ?? 0, divisors.nutritionFullness)
      );
    case "teleport_self":
    case "teleport_target":
    case "reveal":
    case "identify":
      return verbBase;
    case "blink":
      return (
        verbBase +
        ceilDiv(effect.blink?.distanceTiles ?? 0, divisors.blinkDistanceTiles)
      );
    case "knockback":
      return (
        verbBase +
        ceilDiv(effect.knockback?.pushTiles ?? 0, divisors.knockbackPushTiles) +
        ceilDiv(
          effect.knockback?.collisionDamage ?? 0,
          divisors.knockbackCollisionDamage,
        )
      );
    case "enchant":
      return verbBase + (effect.enchant?.bonus ?? 0);
    case "summon":
      return verbBase + ceilDiv(effect.summon?.count ?? 0, divisors.summonCount);
    case "transform":
      return verbBase;
    case "dig":
      return (
        verbBase +
        ceilDiv(effect.dig?.lengthTiles ?? 0, divisors.digLengthTiles)
      );
    default:
      throw new RangeError(`unsupported enemy effect cost ${String(effect.kind)}`);
  }
};

export const triggerCost = (trigger: Trigger): number => {
  const base = costWeights.effects.trigger[trigger.kind];
  const divisors = costWeights.effects.magnitudeDivisors;

  switch (trigger.kind) {
    case "on_hit":
      return (
        base +
        ceilDiv(
          trigger.onHit?.procChancePercent ?? 0,
          divisors.procChancePercent,
        )
      );
    case "on_struck":
      return (
        base +
        ceilDiv(
          trigger.onStruck?.procChancePercent ?? 0,
          divisors.procChancePercent,
        )
      );
    case "use":
      return base + ceilDiv(trigger.use?.charges ?? 0, divisors.useCharges);
    case "quaff":
    case "read":
    case "throw_hit":
    case "equip_passive":
    case "step":
      return base;
    default:
      throw new RangeError(
        `unsupported enemy trigger cost ${String(trigger.kind)}`,
      );
  }
};

export const targetingCost = (targeting: TargetingShape): number => {
  const base = costWeights.effects.targeting[targeting.kind];
  const divisors = costWeights.effects.magnitudeDivisors;

  switch (targeting.kind) {
    case "bolt":
      return (
        base +
        ceilDiv(targeting.bolt?.rangeTiles ?? 0, divisors.boltRangeTiles)
      );
    case "burst":
      return (
        base +
        ceilDiv(targeting.burst?.radiusTiles ?? 0, divisors.burstRadiusTiles)
      );
    case "self":
    case "melee":
    case "floor":
      return base;
    default:
      throw new RangeError(
        `unsupported enemy targeting cost ${String(targeting.kind)}`,
      );
  }
};

const ceilDiv = (value: number, divisor: number): number => {
  if (value <= 0) {
    return 0;
  }

  return Math.ceil(value / divisor);
};

const nonNegativeDelta = (value: number, floor: number): number =>
  Math.max(0, value - floor);

const inRange = (
  value: number,
  range: { readonly min: number; readonly max: number },
): boolean => value >= range.min && value <= range.max;

const clamp = (value: number, min: number, max: number): number =>
  Math.min(max, Math.max(min, value));

