const manhattanDistance = (a: Position, b: Position): number =>
  Math.abs(a.x - b.x) + Math.abs(a.y - b.y);

const positionsEqual = (a: Position, b: Position): boolean =>
  a.x === b.x && a.y === b.y;

const positionKey = (position: Position): string => `${position.x},${position.y}`;

const isExitTerrain = (grid: TileGrid, position: Position): boolean => {
  if (!inBounds(grid, position)) {
    return true;
  }

  const terrain = getTile(grid, position).terrain;
  return terrain === Terrain.Entrance || terrain === Terrain.StairsDown;
};

const sortPositionsStable = (positions: readonly Position[]): Position[] =>
  [...positions].sort((a, b) => (a.y !== b.y ? a.y - b.y : a.x - b.x));

const reachableCellSet = (
  grid: TileGrid,
  entrance: Position,
): ReadonlySet<number> | null => {
  if (!inBounds(grid, entrance)) {
    return null;
  }

  const startIndex = idx(grid, entrance);
  const startTile = grid.tiles[startIndex];
  if (startTile === undefined || !isWalkableTile(startTile)) {
    return null;
  }

  const visited = new Set<number>([startIndex]);
  const queue: number[] = [startIndex];
  let iterations = 0;

  while (queue.length > 0) {
    iterations += 1;
    if (iterations > CONNECTIVITY_ITERATION_CAP) {
      return null;
    }

    const currentIndex = queue.shift();
    if (currentIndex === undefined) {
      break;
    }

    const current = {
      x: currentIndex % grid.width,
      y: Math.floor(currentIndex / grid.width),
    };

    for (const neighbor of neighbors8(grid, current)) {
      const neighborIndex = idx(grid, neighbor);
      if (visited.has(neighborIndex)) {
        continue;
      }

      const tile = grid.tiles[neighborIndex];
      if (tile === undefined || !isWalkableTile(tile)) {
        continue;
      }

      visited.add(neighborIndex);
      queue.push(neighborIndex);
    }
  }

  return visited;
};

export const collectLegalPlacementCells = (
  floor: PlacementGrid,
): readonly Position[] => {
  const reachable = reachableCellSet(floor.grid, floor.entrance);
  if (reachable === null) {
    return [];
  }

  const legal: Position[] = [];

  for (const index of reachable) {
    const position = {
      x: index % floor.grid.width,
      y: Math.floor(index / floor.grid.width),
    };

    if (
      positionsEqual(position, floor.entrance) ||
      positionsEqual(position, floor.stairsDown) ||
      isExitTerrain(floor.grid, position)
    ) {
      continue;
    }

    legal.push(position);
  }

  return sortPositionsStable(legal);
};

const filterByRoomIndex = (
  candidates: readonly Position[],
  rooms: readonly RoomRect[],
  roomIndex: number,
): readonly Position[] =>
  candidates.filter((position) => roomContaining(rooms, position) === roomIndex);

const filterByDistanceHint = (
  candidates: readonly Position[],
  entrance: Position,
  distance: PlacementDistanceHint,
): readonly Position[] => {
  if (candidates.length === 0) {
    return candidates;
  }

  const distances = candidates.map((position) => ({
    position,
    distance: manhattanDistance(position, entrance),
  }));

  const targetDistance =
    distance === "near_entrance"
      ? Math.min(...distances.map((entry) => entry.distance))
      : Math.max(...distances.map((entry) => entry.distance));

  return distances
    .filter((entry) => entry.distance === targetDistance)
    .map((entry) => entry.position);
};

const filterBySpread = (
  candidates: readonly Position[],
  occupied: ReadonlySet<string>,
): readonly Position[] => {
  if (candidates.length === 0 || occupied.size === 0) {
    return candidates;
  }

  const occupiedPositions = [...occupied].map((key) => {
    const [xText, yText] = key.split(",");
    return {
      x: Number(xText),
      y: Number(yText),
    };
  });

  const scored = candidates.map((position) => {
    const minDistance = occupiedPositions.reduce((best, occupiedPosition) => {
      const distance = manhattanDistance(position, occupiedPosition);
      return Math.min(best, distance);
    }, Number.POSITIVE_INFINITY);

    return { position, minDistance };
  });

  const bestSpread = Math.max(...scored.map((entry) => entry.minDistance));
  return scored
    .filter((entry) => entry.minDistance === bestSpread)
    .map((entry) => entry.position);
};

const applyHintFilters = (
  floor: PlacementGrid,
  candidates: readonly Position[],
  hint: PlacementHint | undefined,
  occupied: ReadonlySet<string>,
): {
  readonly hinted: readonly Position[];
  readonly satisfied: boolean;
  readonly reasons: readonly PlacementDeviationReason[];
} => {
  if (hint === undefined) {
    return { hinted: candidates, satisfied: true, reasons: [] };
  }

  let current = candidates;
  const reasons: PlacementDeviationReason[] = [];

  if (hint.roomIndex !== undefined) {
    const inRoom = filterByRoomIndex(current, floor.rooms, hint.roomIndex);
    if (inRoom.length === 0) {
      reasons.push("room_index_unsatisfiable");
      return { hinted: candidates, satisfied: false, reasons };
    }
    current = inRoom;
  }

  if (hint.distance !== undefined) {
    const byDistance = filterByDistanceHint(current, floor.entrance, hint.distance);
    if (byDistance.length === 0) {
      reasons.push("distance_hint_unsatisfiable");
      return { hinted: candidates, satisfied: false, reasons };
    }
    current = byDistance;
  }

  if (hint.spread === true) {
    const spread = filterBySpread(current, occupied);
    if (spread.length === 0) {
      reasons.push("spread_hint_unsatisfiable");
      return { hinted: candidates, satisfied: false, reasons };
    }
    current = spread;
  }

  return { hinted: current, satisfied: true, reasons };
};

const pickPosition = (candidates: readonly Position[], rng: Rng): Position => {
  const ordered = sortPositionsStable(candidates);
  return rng.pick(ordered);
};

export const allocateCells = (
  grid: PlacementGrid,
  requests: readonly PlacementRequest[],
  rng: Rng,
): AllocateCellsResult => {
  const legalCells = collectLegalPlacementCells(grid);

  if (requests.length > legalCells.length) {
    return {
      ok: false,
      error: {
        kind: "allocation-error",
        code: "capacity_exhausted",
        message: `cannot place ${requests.length} entities on ${legalCells.length} legal cells`,
        legalCellCount: legalCells.length,
        requestCount: requests.length,
      },
    };
  }

  const occupied = new Set<string>();
  const placements: PlacementAllocation[] = [];
  const deviations: PlacementDeviation[] = [];

  for (const request of requests) {
    const available = legalCells.filter(
      (position) => !occupied.has(positionKey(position)),
    );

    const { hinted, satisfied, reasons } = applyHintFilters(
      grid,
      available,
      request.hint,
      occupied,
    );

    if (!satisfied && request.hint !== undefined) {
      deviations.push({
        requestId: request.id,
        hint: request.hint,
        reasons,
      });
    }

    const position = pickPosition(satisfied ? hinted : available, rng);
    occupied.add(positionKey(position));
    placements.push({
      requestId: request.id,
      kind: request.kind,
      position,
    });
  }

  return {
    ok: true,
    placements,
    deviations,
  };
};

import type { FloorContentProvider } from "../../engine/run/loop.js";
import type { BotPolicy } from "./types.js";
import { runBot, type BotRunResult, type RunBotOptions } from "./driver.js";

export type BotBatchRow = {
  readonly policy: BotPolicy["name"];
  readonly seed: string;
  readonly terminal: string;
  readonly depth: number;
  readonly turns: number;
  readonly kills: number;
  readonly hpRetention: number;
  readonly itemUses: number;
  readonly tracePath: string;
};

export type BotBatchResult = {
  readonly rows: readonly BotBatchRow[];
  readonly runs: readonly BotRunResult[];
};

export const runBotBatch = (
  policies: readonly BotPolicy[],
  seeds: readonly string[],
  providerFactory: () => FloorContentProvider,
  maxTurns: number,
  options: RunBotOptions = {},
): BotBatchResult => {
  const runs = policies.flatMap((policy) =>
    seeds.map((seed) =>
      runBot(policy, seed, providerFactory(), maxTurns, options),
    ),
  );

  return {
    runs,
    rows: runs.map((run) => ({
      policy: run.policy,
      seed: run.seed,
      terminal: run.outcome.terminal,
      depth: run.outcome.depth,
      turns: run.outcome.turns,
      kills: run.outcome.kills,
      hpRetention: run.outcome.hpRetention,
      itemUses: run.outcome.itemUses,
      tracePath: run.trace.path,
    })),
  };
};

export const formatBotOutcomeTable = (
  rows: readonly BotBatchRow[],
): string => {
  const headers = [
    "policy",
    "seed",
    "terminal",
    "depth",
    "turns",
    "kills",
    "hp%",
    "itemUses",
  ] as const;
  const body = rows.map((row) => [
    row.policy,
    row.seed,
    row.terminal,
    row.depth.toString(),
    row.turns.toString(),
    row.kills.toString(),
    Math.round(row.hpRetention * 100).toString(),
    row.itemUses.toString(),
  ]);
  const widths = headers.map((header, index) =>
    Math.max(header.length, ...body.map((row) => row[index]?.length ?? 0)),
  );
  const line = (cells: readonly string[]) =>
    cells
      .map((cell, index) => cell.padEnd(widths[index] ?? cell.length))
      .join(" | ");

  return [
    line(headers),
    widths.map((width) => "-".repeat(width)).join("-|-"),
    ...body.map(line),
  ].join("\n");
};

import { mkdirSync, writeFileSync } from "node:fs";
import { dirname } from "node:path";
import { pathToFileURL } from "node:url";
import { resolve } from "node:path";

import "../engine/items/triggers.js";
import "../engine/npc/dialogue.js";
import "../engine/systems/combat.js";
import "../engine/systems/inventory.js";
import "../engine/systems/movement.js";

import {
  config,
  type DirectorProviderSelection,
  type GameConfig,
} from "../config/index.js";
import { createDirectorFloorProvider } from "../director/orchestration/prefetch.js";
import { createDirectorProvider } from "../director/provider/index.js";
import type { FloorContentProvider } from "../engine/run/loop.js";
import { createFallbackFloorContentProvider } from "../harness/fallback-provider.js";
import {
  botPolicies,
  formatBotOutcomeTable,
  runBot,
  runBotBatch,
  type BotBatchRow,
} from "../harness/bots/index.js";
import type { BotPolicy, BotPolicyName } from "../harness/bots/types.js";

const DEFAULT_MAX_TURNS = 900;

const policyByName = new Map<BotPolicyName, BotPolicy>(
  botPolicies.map((policy) => [policy.name, policy]),
);

export type SimulateDirectorSelection = Extract<
  DirectorProviderSelection,
  "mock" | "ambient"
>;

export type ParsedSimulateArgs =
  | { readonly help: true }
  | {
      readonly help: false;
      readonly batch: false;
      readonly policy: BotPolicyName;
      readonly seed: string;
      readonly maxTurns: number;
      readonly outPath: string | null;
      readonly director?: SimulateDirectorSelection;
    }
  | {
      readonly help: false;
      readonly batch: true;
      readonly policies: readonly BotPolicyName[];
      readonly seeds: readonly string[];
      readonly maxTurns: number;
      readonly outPath: string | null;
      readonly director?: SimulateDirectorSelection;
    };

export type SimulateResult = {
  readonly rows: readonly BotBatchRow[];
  readonly table: string;
  readonly exitCode: number;
  readonly outPath: string | null;
};

export const SIMULATE_HELP_TEXT = `Generative Gaming — headless bot simulate

Usage:
  pnpm run simulate -- --policy <name> --seed <seed> [--max-turns <n>] [--out <path>]
  pnpm run simulate -- --batch --policies <a,b,c> --seeds <N|s1,s2,...> [--max-turns <n>] [--out <path>]

Policies: cautious, balanced, aggressive

Options:
  --policy <name>       Bot policy for a single run (required unless --batch)
  --seed <seed>         Seed for a single run (default: cli-simulate)
  --batch               Run a policies × seeds sweep
  --policies <list>     Comma-separated policy names (required with --batch)
  --seeds <N|list>      Seed count (simulate-1..N) or comma-separated seed list
  --max-turns <n>       Turn cap per run (default: ${DEFAULT_MAX_TURNS})
  --director <kind>     Use DirectorFloorProvider with mock or ambient provider
  --out <path>          Write JSON outcome rows to this path
  --help, -h            Show this help

Exit code is nonzero when any run is still ACTIVE or hits the turn cap.`;

const cliArgv = (argv: readonly string[] = process.argv.slice(2)): readonly string[] =>
  argv[0] === "--" ? argv.slice(1) : argv;

export const parseSimulateArgs = (
  argv: readonly string[] = cliArgv(),
): ParsedSimulateArgs => {
  let help = false;
  let batch = false;
  let policy: BotPolicyName | null = null;
  let seed = "cli-simulate";
  let policies: BotPolicyName[] = [];
  let seeds: string[] = [];
  let maxTurns = DEFAULT_MAX_TURNS;
  let outPath: string | null = null;
  let director: SimulateDirectorSelection | undefined;

  for (let index = 0; index < argv.length; index += 1) {
    const arg = argv[index];
    if (arg === undefined) {
      continue;
    }

    if (arg === "--help" || arg === "-h") {
      help = true;
      continue;
    }

    if (arg === "--batch") {
      batch = true;
      continue;
    }

    if (arg === "--policy") {
      policy = readPolicyName(argv, index, "--policy");
      index += 1;
      continue;
    }

    if (arg.startsWith("--policy=")) {
      policy = parsePolicyName(arg.slice("--policy=".length));
      continue;
    }

    if (arg === "--seed") {
      seed = readStringValue(argv, index, "--seed");
      index += 1;
      continue;
    }

    if (arg.startsWith("--seed=")) {
      seed = readInlineValue(arg, "--seed");
      continue;
    }

    if (arg === "--policies") {
      policies = readPolicyList(argv, index, "--policies");
      index += 1;
      continue;
    }

    if (arg.startsWith("--policies=")) {
      policies = parsePolicyList(arg.slice("--policies=".length));
      continue;
    }

    if (arg === "--seeds") {
      seeds = parseSeeds(readStringValue(argv, index, "--seeds"));
      index += 1;
      continue;
    }

    if (arg.startsWith("--seeds=")) {
      seeds = parseSeeds(readInlineValue(arg, "--seeds"));
      continue;
    }

    if (arg === "--max-turns") {
      maxTurns = readPositiveInt(argv, index, "--max-turns");
      index += 1;
      continue;
    }

    if (arg.startsWith("--max-turns=")) {
      maxTurns = parsePositiveInt(readInlineValue(arg, "--max-turns"), "--max-turns");
      continue;
    }

    if (arg === "--director") {
      director = readDirectorSelection(argv, index, "--director");
      index += 1;
      continue;
    }

    if (arg.startsWith("--director=")) {
      director = parseDirectorSelection(readInlineValue(arg, "--director"));
      continue;
    }

    if (arg === "--out") {
      outPath = readStringValue(argv, index, "--out");
      index += 1;
      continue;
    }

    if (arg.startsWith("--out=")) {
      outPath = readInlineValue(arg, "--out");
      continue;
    }

    throw new Error(`unknown argument: ${arg}`);
  }

  if (help) {
    return { help: true };
  }

  if (batch) {
    if (policies.length === 0) {
      throw new Error("--batch requires --policies");
    }
    if (seeds.length === 0) {
      throw new Error("--batch requires --seeds");
    }
    return {
      help: false,
      batch: true,
      policies,
      seeds,
      maxTurns,
      outPath,
      ...(director === undefined ? {} : { director }),
    };
  }

  if (policy === null) {
    throw new Error("--policy is required unless --batch is set");
  }

  return {
    help: false,
    batch: false,
    policy,
    seed,
    maxTurns,
    outPath,
    ...(director === undefined ? {} : { director }),
  };
};

export const runSimulate = (args: Exclude<ParsedSimulateArgs, { help: true }>): SimulateResult => {
  let providerCounter = 0;

  let providerCounter = 0;
  const createdAt = new Date().toISOString();
  const providerFactory = () =>
    createSimulateProvider(args.director, providerCounter += 1);

  const batchResult = args.batch
    ? runBotBatch(
        args.policies.map((name) => resolvePolicy(name)),
        args.seeds,
        providerFactory,
        args.maxTurns,
        { createdAt },
      )
    : {
        runs: [
          runBot(
            resolvePolicy(args.policy),
            args.seed,
            providerFactory(),
            args.maxTurns,
            { createdAt },
          ),
        ],
        rows: [] as BotBatchRow[],
      };

  const rows: BotBatchRow[] =
    batchResult.rows.length > 0
      ? [...batchResult.rows]
      : batchResult.runs.map((run) => ({
          policy: run.policy,
          seed: run.seed,
          terminal: run.outcome.terminal,
          depth: run.outcome.depth,
          turns: run.outcome.turns,
          kills: run.outcome.kills,
          hpRetention: run.outcome.hpRetention,
          itemUses: run.outcome.itemUses,
          tracePath: run.trace.path,
        }));

  const table = formatBotOutcomeTable(rows);
  const exitCode = batchResult.runs.some(
    (run) => run.outcome.terminal === "ACTIVE" || run.outcome.maxTurnsHit,
  )
    ? 1
    : 0;

  if (args.outPath !== null) {
    writeSimulateJson(args.outPath, rows, exitCode !== 0);
  }

  return {
    rows,
    table,
    exitCode,
    outPath: args.outPath,
  };
};

const writeSimulateJson = (
  outPath: string,
  rows: readonly BotBatchRow[],
  hasFailures: boolean,
): void => {
  mkdirSync(dirname(resolve(outPath)), { recursive: true });
  writeFileSync(
    outPath,
    `${JSON.stringify({ rows, hasFailures }, null, 2)}\n`,
    "utf8",
  );
};

const resolvePolicy = (name: BotPolicyName): BotPolicy => {
  const policy = policyByName.get(name);
  if (policy === undefined) {
    throw new Error(`unknown policy: ${name}`);
  }
  return policy;
};

const parsePolicyName = (value: string): BotPolicyName => {
  if (!policyByName.has(value as BotPolicyName)) {
    throw new Error(`unknown policy: ${value}`);
  }
  return value as BotPolicyName;
};

const readPolicyName = (
  argv: readonly string[],
  index: number,
  flag: string,
): BotPolicyName => parsePolicyName(readStringValue(argv, index, flag));

const parsePolicyList = (value: string): BotPolicyName[] => {
  const names = value
    .split(",")
    .map((entry) => entry.trim())
    .filter((entry) => entry.length > 0);
  if (names.length === 0) {
    throw new Error("--policies requires at least one policy");
  }
  return names.map((name) => parsePolicyName(name));
};

const readPolicyList = (
  argv: readonly string[],
  index: number,
  flag: string,
): BotPolicyName[] => parsePolicyList(readStringValue(argv, index, flag));

export const parseSeeds = (value: string): string[] => {
  if (/^\d+$/.test(value)) {
    const count = Number.parseInt(value, 10);
    if (count <= 0) {
      throw new Error("--seeds count must be a positive integer");
    }
    return Array.from({ length: count }, (_, seedIndex) => `simulate-${seedIndex + 1}`);
  }

  const seeds = value
    .split(",")
    .map((entry) => entry.trim())
    .filter((entry) => entry.length > 0);
  if (seeds.length === 0) {
    throw new Error("--seeds requires at least one seed");
  }
  return seeds;
};

const readStringValue = (argv: readonly string[], index: number, flag: string): string => {
  const next = argv[index + 1];
  if (next === undefined || next.startsWith("-")) {
    throw new Error(`${flag} requires a value`);
  }
  return next;
};

const readInlineValue = (arg: string, flag: string): string => {
  const value = arg.slice(flag.length + 1);
  if (value.length === 0) {
    throw new Error(`${flag} requires a value`);
  }
  return value;
};

const readDirectorSelection = (
  argv: readonly string[],
  index: number,
  flag: string,
): SimulateDirectorSelection =>
  parseDirectorSelection(readStringValue(argv, index, flag));

const parseDirectorSelection = (value: string): SimulateDirectorSelection => {
  if (value === "mock" || value === "ambient") {
    return value;
  }

  throw new Error(`unknown director provider: ${value}`);
};

const readPositiveInt = (argv: readonly string[], index: number, flag: string): number =>
  parsePositiveInt(readStringValue(argv, index, flag), flag);

const parsePositiveInt = (value: string, flag: string): number => {
  const parsed = Number.parseInt(value, 10);
  if (!Number.isSafeInteger(parsed) || parsed <= 0) {
    throw new Error(`${flag} must be a positive integer`);
  }
  return parsed;
};

const createSimulateProvider = (
  director: SimulateDirectorSelection | undefined,
  providerIndex: number,
): FloorContentProvider => {
  if (director === undefined) {
    return createFallbackFloorContentProvider();
  }

  return createDirectorFloorProvider({
    runId: `simulate-${director}-${providerIndex}`,
    seed: `simulate-${director}-${providerIndex}`,
    modelId: `director:${director}`,
    provider: createDirectorProvider({
      config: configWithDirector(director),
    }),
  });
};

const configWithDirector = (
  provider: SimulateDirectorSelection,
): GameConfig => ({
  ...config,
  director: {
    ...config.director,
    provider,
  },
});

const isMainModule = (): boolean => {
  const entry = process.argv[1];
  if (entry === undefined) {
    return false;
  }

  return import.meta.url === pathToFileURL(resolve(entry)).href;
};

const main = (): void => {
  let args: ParsedSimulateArgs;

  try {
    args = parseSimulateArgs();
  } catch (error) {
    const message = error instanceof Error ? error.message : String(error);
    process.stderr.write(`${message}\n`);
    process.exitCode = 1;
    return;
  }

  if (args.help) {
    process.stdout.write(`${SIMULATE_HELP_TEXT}\n`);
    return;
  }

  try {
    const result = runSimulate(args);
    process.stdout.write(`${result.table}\n`);
    process.exitCode = result.exitCode;
  } catch (error) {
    const message = error instanceof Error ? error.message : String(error);
    process.stderr.write(`${message}\n`);
    process.exitCode = 1;
  }
};

if (isMainModule()) {
  main();
}

