/bin/zsh -lc "node --input-type=module <<'NODE'
import { readFileSync } from 'node:fs';
const rows=JSON.parse(readFileSync('/tmp/balance-v2-before-balanced5.json','utf8')).rows;
for(const row of rows){
  const text=readFileSync(row.tracePath,'utf8').trim().split('\\n').slice(1);
  let depth=1; const byDepth={}; const levelUps=[]; const equips=[]; const heals=[];
  for(const line of text){
    const rec=JSON.parse(line);
    for(const ev of rec.events){
      if(ev.type==='run_floor_entered') depth=ev.data.depth;
      const d=String(depth); byDepth[d]??={taken:0, hits:0, enemyHits:0, playerHits:0, playerDamage:0, kills:0, levelUps:0, heals:0};
      if(ev.type==='attack_hit'){
        if(ev.data.defenderId==='player'){ byDepth[d].taken+=ev.data.damage; byDepth[d].enemyHits++; }
        if(ev.data.actorId==='player'){ byDepth[d].playerDamage+=ev.data.damage; byDepth[d].playerHits++; }
      }
      if(ev.type==='entity_died' && ev.data.kind==='enemy') byDepth[d].kills++;
      if(ev.type==='level_up'){ byDepth[d].levelUps++; levelUps.push("'`d${d}:${ev.data.levelBefore}->${ev.data.levelAfter} hp ${ev.data.currentHpBefore}->${ev.data.currentHpAfter}/${ev.data.maxHpAfter}`); }
      if(ev.type==='"'item_equipped') equips.push("'`d${d}:${ev.data.definitionId}`);
      if(ev.type==='"'effect_applied' && ev.data.effectKind==='heal') { byDepth[d].heals+=(ev.data.amount??0); heals.push("'`d${d}:${ev.data.amount}`); }
      if(ev.type==='"'hp_changed' && ev.data.reason==='heal') { byDepth[d].heals+=(ev.data.amount??0); }
    }
  }
  console.log("'`RUN ${row.seed} ${row.terminal} d${row.depth} t${row.turns} kills=${row.kills} items=${row.itemUses}`);
  console.log('"'  depths', Object.entries(byDepth).map(([d,v])=>"'`d${d}:taken${v.taken}/eHits${v.enemyHits}/pDmg${v.playerDamage}/pHits${v.playerHits}/kills${v.kills}/lvl${v.levelUps}/heal${v.heals}`).join('"' | '));
  console.log('  levelUps', levelUps.join(', ')||'-');
  console.log('  equips', equips.join(', ')||'-');
  console.log('  heals', heals.join(', ')||'-');
}
NODE"

