  decide: (view) => {
    const adjacent = adjacentEnemies(view);

    return (
      takeHoardIfAvailable(view) ??
      (view.player.hp.ratio < 0.5 ? useHealingItem(view, true) : null) ??
      useEquipmentUpgrade(view) ??
      useThrowableAgainstEnemy(
