/bin/zsh -lc "node --input-type=module <<'NODE'
import { readFileSync } from 'node:fs';
const rows=JSON.parse(readFileSync('/tmp/balance-v2-final-45.json','utf8')).rows;
const byPolicy = new Map();
const byTerminal = new Map();
const byDepth = new Map();
let illegalHoard=0, d12Aborts=0, d12Illegal=0, shallowDeaths=0;
const lossDepths=[];
for (const r of rows) {
  byPolicy.set(r.policy, byPolicy.get(r.policy) ?? {runs:0, WIN:0, ABORTED:0, LOSS:0, depths:{}});
  const p=byPolicy.get(r.policy); p.runs++; p[r.terminal]++; p.depths[r.depth]=(p.depths[r.depth]??0)+1;
  byTerminal.set(r.terminal, (byTerminal.get(r.terminal)??0)+1);
  byDepth.set(r.depth, (byDepth.get(r.depth)??0)+1);
  if (r.terminal==='LOSS') { lossDepths.push(r.depth); if (r.depth<=2) shallowDeaths++; }
  if (r.terminal==='ABORTED' && r.depth===12) d12Aborts++;
  const text=readFileSync(r.tracePath,'utf8');
  const count=(text.match(/player is not standing at the Hoard/g)||[]).length;
  if (count>0) { illegalHoard += count; if (r.depth===12 && r.terminal==='ABORTED') d12Illegal++; }
}
const median = (xs)=>{ xs=[...xs].sort((a,b)=>a-b); if("'!xs.length) return null; const m=Math.floor(xs.length/2); return xs.length%2?xs[m]:(xs[m-1]+xs[m])/2; };
console.log('"'overall', Object.fromEntries(byTerminal), 'runs', rows.length);
console.log('byPolicy');
for (const [policy, v] of byPolicy) console.log(policy, v);
console.log('terminalDepths', Object.fromEntries([...byDepth].sort((a,b)=>a[0]-b[0])));
console.log('lossDepths', lossDepths.join(','), 'medianLossDepth', median(lossDepths), 'shallowDeaths', shallowDeaths);
console.log('d12Aborts', d12Aborts, 'illegalHoardEvents', illegalHoard, 'd12AbortsWithIllegalHoard', d12Illegal);
NODE"

